class Solution:
    def smallestChair(self, times, targetFriend):
        target_arrival = times[targetFriend][0]
        order = sorted(range(len(times)), key=lambda i: times[i][0])
        occupied = {}
        for idx in order:
            arr, leave = times[idx]
            for chair in list(occupied):
                if occupied[chair] <= arr:
                    del occupied[chair]
            chair = 0
            while chair in occupied:
                chair += 1
            occupied[chair] = leave
            if arr == target_arrival:
                return chair
        return -1

