var smallestChair = function(times, targetFriend) {
    const targetArrival = times[targetFriend][0];
    const n = times.length;
    const order = [...Array(n).keys()].sort((a, b) => times[a][0] - times[b][0]);
    const free = new MinHeap((a, b) => a - b);
    for (let i = 0; i < n; i++) free.push(i);
    const occupied = new MinHeap((a, b) => a[0] - b[0]);
    for (const idx of order) {
        const arr = times[idx][0], leave = times[idx][1];
        while (occupied.size() && occupied.peek()[0] <= arr) {
            const [, ch] = occupied.pop();
            free.push(ch);
        }
        const chair = free.pop();
        if (arr === targetArrival) return chair;
        occupied.push([leave, chair]);
    }
    return -1;
};

function MinHeap(cmp) {
    const h = [];
    this.size = () => h.length;
    this.peek = () => h[0];
    this.push = (v) => {
        h.push(v);
        let i = h.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (cmp(h[i], h[p]) < 0) { [h[i], h[p]] = [h[p], h[i]]; i = p; } else break;
        }
    };
    this.pop = () => {
        const top = h[0];
        const last = h.pop();
        if (h.length) {
            h[0] = last;
            let i = 0;
            while (true) {
                let l = 2 * i + 1, r = 2 * i + 2, s = i;
                if (l < h.length && cmp(h[l], h[s]) < 0) s = l;
                if (r < h.length && cmp(h[r], h[s]) < 0) s = r;
                if (s !== i) { [h[i], h[s]] = [h[s], h[i]]; i = s; } else break;
            }
        }
        return top;
    };
}
